def clean_val(val):
    val = val.strip()
    if val.upper() == 'NULL':
        return None
    if val.startswith("'") and val.endswith("'"):
        return val[1:-1]
    return val

doctor_price_list = []
for line in raw_data.strip().split('\n'):
    parts = line.split(',')
    if len(parts) < 13:
        continue
    
    entry = {
        "id": int(clean_val(parts[0])),
        "DoctorID": clean_val(parts[1]),
        "ItemID": clean_val(parts[2]),
        "WardTypeID": clean_val(parts[3]),
        "Specialization": clean_val(parts[4]),
        "Price": float(clean_val(parts[5])),
        "BranchID": clean_val(parts[6]),
        "DepartmentID": clean_val(parts[7]),
        "CreatedStaffID": clean_val(parts[8]),
        "CreatedDateTime": clean_val(parts[9]),
        "UpdatedStaffID": clean_val(parts[10]),
        "UpdatedDateTime": clean_val(parts[11]),
        "IsRowDeleted": clean_val(parts[12])
    }
    doctor_price_list.append(entry)

with open(db_path, 'r', encoding='utf-8') as f:
    db = json.load(f)

db['doctor_price'] = doctor_price_list

with open(db_path, 'w', encoding='utf-8') as f:
    json.dump(db, f, indent=2)

